flow-diagram.createChart:
{
/* === Axis rows (rowPadding: 0, minContentHeight: 0 so items fill the entire row height) === */

r_year    = reactFlowGanttRow(model: "axis:year",    label: reactFlowPadding(reactFlowText("Year"),    all: 4), acceptsDrop: false, backgroundColor: "#f0f0f0", borderColor: "#d0d0d0", rowPadding: 0, minContentHeight: 0);
r_months  = reactFlowGanttRow(model: "axis:months",  label: reactFlowPadding(reactFlowText("Month"),   all: 4), acceptsDrop: false, backgroundColor: "#f8f8f8", borderColor: "#d0d0d0", rowPadding: 0, minContentHeight: 0);
r_markers = reactFlowGanttRow(model: "axis:markers", label: reactFlowPadding(reactFlowText("Markers"), all: 4), acceptsDrop: false, backgroundColor: "#f8f8f8", borderColor: "#d0d0d0", rowPadding: 0, minContentHeight: 0);

/* Jan 1 2026 = day 20454, Dec 31 2026 = day 20819 */
year2026 = reactFlowGanttSpan(
	model: "axis:year:2026", rowModel: "axis:year",
	box: reactFlowBorder(reactFlowAlign(reactFlowPadding(reactFlowText("2026"), all: 4), vAlign: "CENTER")),
	start: 20454, end: 20819,
	canMove: false, canResize: false, canBeEdge: false);

/* Month spans with borders */
mFeb = reactFlowGanttSpan(model: "m:feb", rowModel: "axis:months",
	box: reactFlowBorder(reactFlowAlign(reactFlowPadding(reactFlowText("Feb"), all: 2), vAlign: "CENTER")),
	start: 20485, end: 20513, canMove: false, canResize: false, canBeEdge: false);
mMar = reactFlowGanttSpan(model: "m:mar", rowModel: "axis:months",
	box: reactFlowBorder(reactFlowAlign(reactFlowPadding(reactFlowText("Mar"), all: 2), vAlign: "CENTER")),
	start: 20513, end: 20544, canMove: false, canResize: false, canBeEdge: false);
mApr = reactFlowGanttSpan(model: "m:apr", rowModel: "axis:months",
	box: reactFlowBorder(reactFlowAlign(reactFlowPadding(reactFlowText("Apr"), all: 2), vAlign: "CENTER")),
	start: 20544, end: 20574, canMove: false, canResize: false, canBeEdge: false);
mMay = reactFlowGanttSpan(model: "m:may", rowModel: "axis:months",
	box: reactFlowBorder(reactFlowAlign(reactFlowPadding(reactFlowText("May"), all: 2), vAlign: "CENTER")),
	start: 20574, end: 20600, canMove: false, canResize: false, canBeEdge: false);

/* Freeze label in Markers row */
freezeLabel = reactFlowGanttSpan(model: "marker:freeze", rowModel: "axis:markers",
	box: reactFlowBorder(reactFlowAlign(reactFlowPadding(reactFlowText("Freeze"), all: 2), vAlign: "CENTER")),
	start: 20513, end: 20520, canMove: false, canResize: false, canBeEdge: false);

/* === Data rows (default rowPadding: 4) === */

r_design = reactFlowGanttRow(model: "phase:design", label: reactFlowPadding(reactFlowText("Design"),         all: 4), backgroundColor: "#ffffff", borderColor: "#e0e0e0");
r_impl   = reactFlowGanttRow(model: "phase:impl",   label: reactFlowPadding(reactFlowText("Implementation"), all: 4), backgroundColor: "#f5f5f5", borderColor: "#e0e0e0");
r_test   = reactFlowGanttRow(model: "phase:test",   label: reactFlowPadding(reactFlowText("Testing"),        all: 4), backgroundColor: "#ffffff", borderColor: "#e0e0e0");

/* === Items === */

spec  = reactFlowGanttSpan(model: "task:spec",  rowModel: "phase:design",
	box: reactFlowFill(reactFlowBorder(reactFlowPadding(reactFlowText("Spec"),  all: 3)), fill: "#d4e6f9"), start: 20454, end: 20485);
build = reactFlowGanttSpan(model: "task:build", rowModel: "phase:impl",
	box: reactFlowFill(reactFlowBorder(reactFlowPadding(reactFlowText("Build"), all: 3)), fill: "#c8e6c9"), start: 20485, end: 20544,
	validDropTargets: list("phase:impl", "phase:test"));
beta  = reactFlowGanttPoint(model: "milestone:beta", rowModel: "phase:test",
	box: reactFlowFill(reactFlowBorder(reactFlowPadding(reactFlowText("Beta"),  all: 3)), fill: "#fff3cd"), at: 20544);
qa    = reactFlowGanttSpan(model: "task:qa",   rowModel: "phase:test",
	box: reactFlowFill(reactFlowBorder(reactFlowPadding(reactFlowText("QA"),    all: 3)), fill: "#f8d7da"), start: 20544, end: 20574);

fixed_row = reactFlowGanttSpan(model: "task:fixed-row", rowModel: "phase:design",
	box: reactFlowFill(reactFlowBorder(reactFlowPadding(reactFlowText("Fixed Row"), all: 3)), fill: "#e0d4f9"),
	start: 20470, end: 20478, canMoveRow: false);
no_resize = reactFlowGanttSpan(model: "task:no-resize", rowModel: "phase:impl",
	box: reactFlowFill(reactFlowBorder(reactFlowPadding(reactFlowText("No Resize"), all: 3)), fill: "#fce4b8"),
	start: 20490, end: 20500, canResize: false);

/* === Edges === */

e1 = reactFlowGanttEdge(model: "dep:spec->build", sourceModel: "task:spec",  sourceEndpoint: "END", targetModel: "task:build",     targetEndpoint: "START", enforce: "STRICT",
	strokeColor: "#808080", dashes: list(4, 3));
e2 = reactFlowGanttEdge(model: "dep:build->beta", sourceModel: "task:build", sourceEndpoint: "END", targetModel: "milestone:beta", targetEndpoint: "START",
	strokeColor: "#808080",
	violatedStrokeColor: "#d01030", violatedStrokeWidth: 2.0);

/* === Decorations === */

/* Grid lines at month boundaries */
gl_feb = reactFlowGanttLineDeco(model: "grid:feb", at: 20485, color: "#888888", strokeWidth: 0.5);
gl_mar = reactFlowGanttLineDeco(model: "grid:mar", at: 20513, color: "#888888", strokeWidth: 0.5);
gl_apr = reactFlowGanttLineDeco(model: "grid:apr", at: 20544, color: "#888888", strokeWidth: 0.5);
gl_may = reactFlowGanttLineDeco(model: "grid:may", at: 20574, color: "#888888", strokeWidth: 0.5);

/* Freeze range (colored strip — no label here, label is in Markers row) */
freeze = reactFlowGanttRangeDeco(model: "freeze", from: 20513, to: 20520, color: "rgba(255,100,100,0.3)");

/* === Axis config === */

axis = reactFlowGanttAxis(providerId: "days-since-epoch", rangeMin: 20450, rangeMax: 20600, zoom: 8);

reactFlowGantt(
	rootRows:    list($r_year, $r_months, $r_markers, $r_design, $r_impl, $r_test),
	items:       list($year2026, $mFeb, $mMar, $mApr, $mMay, $freezeLabel, $spec, $build, $beta, $qa, $fixed_row, $no_resize),
	edges:       list($e1, $e2),
	decorations: list($gl_feb, $gl_mar, $gl_apr, $gl_may, $freeze),
	axis: $axis
)
}
